export default words;

export function getWordsByLesson(lesson: number): Word[] {
  return words.filter((w) => w.lesson === lesson);
}

export function getAllLessons(): number[] {
  return [...new Set(words.map((w) => w.lesson))].sort((a, b) => a - b);
}

export function normalizeAnswer(s: string): string {
  return s.toLowerCase().replace(/[-\s]/g, "").trim();
}

export function checkAnswer(input: string, accepted: string[]): boolean {
  const norm = normalizeAnswer(input);
  return accepted.some((a) => normalizeAnswer(a) === norm);
}

/** Pick `count` random words from the lesson pool, shuffled. */
export function sampleWords(lesson: number, count = 10): Word[] {
  const pool = getWordsByLesson(lesson);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(count, shuffled.length));
}
